@@ -1044,22 +1044,14 @@ Value *InstCombinerImpl::SimplifyDemandedUseBits(Instruction *I,
               SimplifyDemandedBits(I, 1, DemandedMaskRHS, RHSKnown, Depth + 1,
                                    Q))
             return I;
-        } else { // fshl is a rotate
-          // Avoid converting rotate into funnel shift.
-          // Only simplify if one operand is constant.
+        } else { // Operands are identical: this is a rotate pattern.
+          // Do not attempt to replace one of the operands with a partial
+          // constant based on demanded bits. A rotate permutes all bits of the
+          // single input value; substituting a constant for only the demanded
+          // slice is not semantics-preserving unless the entire operand is
+          // known. Just compute known bits once and use for both sides.
           LHSKnown = computeKnownBits(I->getOperand(0), Depth + 1, I);
-          if (DemandedMaskLHS.isSubsetOf(LHSKnown.Zero | LHSKnown.One) &&
-              !match(I->getOperand(0), m_SpecificInt(LHSKnown.One))) {
-            replaceOperand(*I, 0, Constant::getIntegerValue(VTy, LHSKnown.One));
