-          if (DemandedMaskRHS.isSubsetOf(RHSKnown.Zero | RHSKnown.One) &&
-              !match(I->getOperand(1), m_SpecificInt(RHSKnown.One))) {
-            replaceOperand(*I, 1, Constant::getIntegerValue(VTy, RHSKnown.One));
-            return I;
-          }
+          RHSKnown = LHSKnown;
         }

         Known.Zero = LHSKnown.Zero.shl(ShiftAmt) |
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
index 943598a30f04..724e65229fc7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
@@ -1044,21 +1044,35 @@ Value *InstCombinerImpl::SimplifyDemandedUseBits(Instruction *I,
               SimplifyDemandedBits(I, 1, DemandedMaskRHS, RHSKnown, Depth + 1,
                                    Q))
             return I;
-        } else { // fshl is a rotate
-          // Avoid converting rotate into funnel shift.
-          // Only simplify if one operand is constant.
-          LHSKnown = computeKnownBits(I->getOperand(0), Depth + 1, I);
-          if (DemandedMaskLHS.isSubsetOf(LHSKnown.Zero | LHSKnown.One) &&
-              !match(I->getOperand(0), m_SpecificInt(LHSKnown.One))) {
-            replaceOperand(*I, 0, Constant::getIntegerValue(VTy, LHSKnown.One));
-            return I;
-          }
+        } else { // Operands are identical: this is a rotate pattern.
+          // Only try to simplify based on demanded bits if we are *not*
+          // computing full-known-bits (i.e. some result bits are genuinely
+          // undemanded by the caller). When all bits are demanded, replacing
+          // one operand with a partial constant is not semantics-preserving
+          // because a rotate permutes all bits of the single input value.
+          if (!DemandedMask.isAllOnes()) {
+            // Avoid converting rotate into funnel shift. Only simplify if one
+            // operand slice is fully known constant for the demanded portion.
+            LHSKnown = computeKnownBits(I->getOperand(0), Depth + 1, I);
+            if (DemandedMaskLHS.isSubsetOf(LHSKnown.Zero | LHSKnown.One) &&
+                !match(I->getOperand(0), m_SpecificInt(LHSKnown.One))) {
+              replaceOperand(*I, 0,
+                             Constant::getIntegerValue(VTy, LHSKnown.One));
+              return I;
+            }

-          RHSKnown = computeKnownBits(I->getOperand(1), Depth + 1, I);
-          if (DemandedMaskRHS.isSubsetOf(RHSKnown.Zero | RHSKnown.One) &&
-              !match(I->getOperand(1), m_SpecificInt(RHSKnown.One))) {
-            replaceOperand(*I, 1, Constant::getIntegerValue(VTy, RHSKnown.One));
-            return I;
+            RHSKnown = computeKnownBits(I->getOperand(1), Depth + 1, I);
+            if (DemandedMaskRHS.isSubsetOf(RHSKnown.Zero | RHSKnown.One) &&
+                !match(I->getOperand(1), m_SpecificInt(RHSKnown.One))) {
+              replaceOperand(*I, 1,
+                             Constant::getIntegerValue(VTy, RHSKnown.One));
+              return I;
+            }
+          } else {
+            // Full-demand case: just compute known bits once and use for both
+            // sides without changing operands.
+            LHSKnown = computeKnownBits(I->getOperand(0), Depth + 1, I);
+            RHSKnown = LHSKnown;
           }
         }

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
index 943598a30f04..c06964c51259 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
@@ -1044,21 +1044,36 @@ Value *InstCombinerImpl::SimplifyDemandedUseBits(Instruction *I,
               SimplifyDemandedBits(I, 1, DemandedMaskRHS, RHSKnown, Depth + 1,
                                    Q))
             return I;
-        } else { // fshl is a rotate
-          // Avoid converting rotate into funnel shift.
-          // Only simplify if one operand is constant.
