-          if (DemandedMaskLHS.isSubsetOf(LHSKnown.Zero | LHSKnown.One) &&
-              !match(I->getOperand(0), m_SpecificInt(LHSKnown.One))) {
-            replaceOperand(*I, 0, Constant::getIntegerValue(VTy, LHSKnown.One));
-            return I;
-          }
+        } else { // Operands are identical: this is a rotate pattern.
+          // If there is range metadata on the intrinsic result, do not mutate
+          // the operands based on partial demanded bits because that may
+          // invalidate the metadata and introduce poison.
+          if (I->hasMetadata(LLVMContext::MD_range)) {
+            LHSKnown = computeKnownBits(I->getOperand(0), Depth + 1, I);
+            RHSKnown = LHSKnown;
+          } else if (!DemandedMask.isAllOnes()) {
+            // Avoid converting rotate into funnel shift. Only simplify if one
+            // operand slice is fully known constant for the demanded portion.
+            LHSKnown = computeKnownBits(I->getOperand(0), Depth + 1, I);
+            if (DemandedMaskLHS.isSubsetOf(LHSKnown.Zero | LHSKnown.One) &&
+                !match(I->getOperand(0), m_SpecificInt(LHSKnown.One))) {
+              replaceOperand(*I, 0,
+                             Constant::getIntegerValue(VTy, LHSKnown.One));
+              return I;
+            }

-          RHSKnown = computeKnownBits(I->getOperand(1), Depth + 1, I);
-          if (DemandedMaskRHS.isSubsetOf(RHSKnown.Zero | RHSKnown.One) &&
-              !match(I->getOperand(1), m_SpecificInt(RHSKnown.One))) {
-            replaceOperand(*I, 1, Constant::getIntegerValue(VTy, RHSKnown.One));
-            return I;
+            RHSKnown = computeKnownBits(I->getOperand(1), Depth + 1, I);
+            if (DemandedMaskRHS.isSubsetOf(RHSKnown.Zero | RHSKnown.One) &&
+                !match(I->getOperand(1), m_SpecificInt(RHSKnown.One))) {
+              replaceOperand(*I, 1,
+                             Constant::getIntegerValue(VTy, RHSKnown.One));
+              return I;
+            }
+          } else {
+            // Full-demand case: just compute known bits once and use for both
+            // sides without changing operands.
+            LHSKnown = computeKnownBits(I->getOperand(0), Depth + 1, I);
+            RHSKnown = LHSKnown;
           }
         }

